import {
  ChangeDetectorRef,
  Component,
  ElementRef,
  OnInit,
  ViewChild,
} from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { pagingService } from "src/app/core/services/paging.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { VendorService } from "src/app/core/services/vendor.service";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import {
  AddCategory,
  Category,
  DeleteCategory,
  EditCategory,
} from "src/app/views/Models/Vendor/category";

@Component({
  selector: "app-manage-categories",
  templateUrl: "./manage-categories.page.html",
  styleUrls: ["./manage-categories.page.scss"],
})
export class ManageCategoriesPage implements OnInit {
  @ViewChild("categoryContainer") categoryContainer!: ElementRef;

  //#region Flags
  showLoader: boolean = false;
  openCreateModal: boolean = false;
  openEditModal: boolean = false;
  //#endregion Flags
  //#region Variables
  categories: Category[];
  selectedCategory: Category[];
  filteredCategories: Category[];
  breadcrumbs: Category[] = [];
  currentParentCatCode: number = null;
  page: number = 1;
  searchTerm: string = "";
  namingRef: StaticRef[];
  //#endregion
  //#region Forms
  categoryForm: FormGroup = this.formbuilder.group({
    catCode: [null],
    catName: ["", [Validators.required, this.noWhitespaceValidator]],
    parentCatCode: [null],
    leafCat: [0],
    activeRec: [1],
    uuc: [""],
  });
  //#endregion

  constructor(
    public vendorService: VendorService,
    public alertService: AlertService,
    public formbuilder: FormBuilder,
    public pagingService: pagingService,
    private cdref: ChangeDetectorRef,
    private referencesService: ReferencesService
  ) {}

  noWhitespaceValidator(control: FormControl) {
    const isWhitespace = (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }

  async ngOnInit() {
    this.showLoader = true;
    this.namingRef = await this.referencesService
      .getCategoriesItemsRef()
      .toPromise();
    this.categories = await this.vendorService.getCategories();
    this.selectedCategory = this.categories;
    this.filteredCategories = this.categories;
    this.showLoader = false;
  }

  ngAfterContentChecked(): void {
    this.cdref.detectChanges();
  }

  async navigateCategory(cat: Category) {
    const element = this.categoryContainer.nativeElement;
    element.classList.add("swipe-right");
    await new Promise((resolve) => {
      element.addEventListener(
        "animationend",
        () => {
          resolve(true);
        },
        { once: true }
      );
    });

    this.showLoader = true;
    this.currentParentCatCode = cat.catCode;
    if (!this.breadcrumbs.includes(cat)) {
      this.breadcrumbs.push(cat);
    } else {
      if (this.breadcrumbs.indexOf(cat) + 1 < this.breadcrumbs.length) {
        this.breadcrumbs = this.breadcrumbs.slice(
          0,
          this.breadcrumbs.indexOf(cat) + 1
        );
      }
    }
    this.selectedCategory = cat.subCategories;
    this.filteredCategories = cat.subCategories;
    this.searchTerm = "";
    this.page = 1;
    this.showLoader = false;
    element.classList.remove("swipe-right");
  }

  changePage(newPage: number): void {
    this.page = newPage;
  }

  async returnToHome() {
    if (this.selectedCategory === this.categories) return;

    const element = this.categoryContainer.nativeElement;
    element.classList.add("swipe-right");
    await new Promise((resolve) => {
      element.addEventListener(
        "animationend",
        () => {
          resolve(true);
        },
        { once: true }
      );
    });
    this.showLoader = true;
    this.breadcrumbs = [];
    this.selectedCategory = this.categories;
    this.filteredCategories = this.categories;
    this.currentParentCatCode = null;
    this.page = 1;
    this.searchTerm = "";
    this.showLoader = false;
    element.classList.remove("swipe-right");
  }

  async back() {
    this.showLoader = true;
    this.breadcrumbs.pop();
    if (this.breadcrumbs.length > 0) {
      this.navigateCategory(this.breadcrumbs[this.breadcrumbs.length - 1]);
    } else {
      const element = this.categoryContainer.nativeElement;
      element.classList.add("swipe-right");
      await new Promise((resolve) => {
        element.addEventListener(
          "animationend",
          () => {
            resolve(true);
          },
          { once: true }
        );
      });
      this.selectedCategory = this.categories;
      this.filteredCategories = this.categories;
      this.currentParentCatCode = null;
      this.page = 1;
      this.searchTerm = "";
      element.classList.remove("swipe-right");
    }
    this.showLoader = false;
  }

  openAddCategoryModal() {
    this.categoryForm.patchValue({
      catName: "",
      parentCatCode: this.currentParentCatCode,
      leafCat: 0,
      activeRec: 1,
    });
    this.openCreateModal = true;
  }

  closeModal() {
    this.openCreateModal = false;
    this.openEditModal = false;
    this.categoryForm.reset();
  }

  getParentCategoryName(): string | undefined {
    const findCategoryByCode = (
      categories: Category[],
      code: number
    ): Category | undefined => {
      for (const cat of categories) {
        if (cat.catCode === code) {
          return cat;
        }
        if (cat.subCategories && cat.subCategories.length > 0) {
          const found = findCategoryByCode(cat.subCategories, code);
          if (found) return found;
        }
      }
      return undefined;
    };

    const category = findCategoryByCode(
      this.categories,
      this.currentParentCatCode
    );
    return category?.catName;
  }

  async addNewCategory() {
    this.showLoader = true;
    if (!this.categoryForm.valid) {
      this.alertService.showAlertError(
        "يجب ادخال اسم ال" + this.getNamingRefValue("2"),
        false
      );
      this.showLoader = false;
      return;
    } else {
      let newCategory: AddCategory = {
        catName: this.categoryForm.value.catName,
        parentCatCode: this.currentParentCatCode,
        leafCat: this.categoryForm.value.leafCat === true ? 1 : 0,
        activeRec: this.categoryForm.value.activeRec === true ? 1 : 0,
      };
      await this.vendorService
        .addCategory(newCategory)
        .then(() => {
          this.alertService.showAlertConfirm("تمت الاضافة بنجاح", true);
        })
        .catch((err) => {
          this.alertService.showAlertError(err.error, false);
        });
      this.showLoader = false;
    }
  }

  openEditCategoryModal(cat: Category) {
    this.categoryForm.patchValue({
      catCode: cat.catCode,
      catName: cat.catName,
      parentCatCode: this.currentParentCatCode,
      leafCat: cat.leafCat,
      activeRec: cat.activeRec,
      uuc: cat.uuc,
    });
    this.openEditModal = true;
  }

  async editCategory() {
    this.showLoader = true;
    if (!this.categoryForm.valid) {
      this.alertService.showAlertError(
        "يجب ادخال اسم ال" + this.getNamingRefValue("2"),
        false
      );
      this.showLoader = false;
      return;
    } else {
      let editCategory: EditCategory = {
        catCode: this.categoryForm.value.catCode,
        catName: this.categoryForm.value.catName,
        parentCatCode: this.currentParentCatCode,
        leafCat: this.categoryForm.value.leafCat === true ? 1 : 0,
        activeRec: this.categoryForm.value.activeRec === true ? 1 : 0,
        uuc: this.categoryForm.value.uuc.toString(),
      };
      await this.vendorService
        .editCategory(editCategory)
        .then(() => {
          this.alertService.showAlertConfirm("تمت التعديل بنجاح", true);
        })
        .catch((err) => {
          this.alertService.showAlertError(err.error, false);
        });
      this.showLoader = false;
    }
  }

  async deleteCategory(cat: Category) {
    if (
      await this.alertService.SaveAlert(
        "هل أنت متأكد من حذف هذه ال" + this.getNamingRefValue("2") + "؟"
      )
    ) {
      this.showLoader = true;
      let deleteCategory: DeleteCategory = {
        catCode: cat.catCode,
        uuc: cat.uuc.toString(),
      };
      await this.vendorService
        .deleteCategory(deleteCategory)
        .then(async () => {
          await this.alertService.showAlertConfirm("تمت الحذف بنجاح", true);
        })
        .catch(async (err) => {
          await this.alertService.showAlertError(err.error, false);
        });
      this.showLoader = false;
    }
  }

  search($event: Event) {
    const input = $event.target as HTMLInputElement;
    this.searchTerm = input.value;
    this.page = 1;

    this.filteredCategories = this.selectedCategory.filter(
      (v) =>
        this.searchTerm == "" ||
        v.catName.toLowerCase().match(this.searchTerm.toLowerCase())
    );
  }

  getNamingRefValue(code: string): string {
    const ref = this.namingRef?.find((ref) => ref.ref_code === code);
    return ref?.ref_desc ?? "";
  }
}
